{"code": "import json

# Get NYSE non-ETF stock data with company names
nyse_file_path = locals()['var_functions.query_db:2']
with open(nyse_file_path, 'r') as f:
    nyse_stocks = json.load(f)

# Create symbol to name mapping
symbol_to_name = {record['Symbol']: record['Company Description'] for record in nyse_stocks}
symbols = list(symbol_to_name.keys())

# We'll build a comprehensive list of queries
# For analysis, we need to check each symbol's 2017 data
results = []

for symbol in symbols:
    results.append({
        'symbol': symbol,
        'name': symbol_to_name[symbol],
        'query': f"SELECT '{symbol}' as sym, SUM(CASE WHEN Close > Open THEN 1 ELSE 0 END) as up_days, SUM(CASE WHEN Close < Open THEN 1 ELSE 0 END) as down_days FROM {symbol} WHERE Date >= '2017-01-01' AND Date <= '2017-12-31'"
    })

print(f"Generated queries for {len(results)} NYSE non-ETF stocks")
print("__RESULT__:")
print(json.dumps({
    "count": len(results),
    "queries_sample": results[:3]
}))"}
